#!/usr/bin/env dotnet
// friday13.cs — Find earliest Friday the 13th and count them in a 400-year cycle

// Find the earliest Friday the 13th starting from 0001-01-01 (proleptic Gregorian)
var date = new DateTime(1, 1, 13); // start checking the 13th of each month
while (date.DayOfWeek != DayOfWeek.Friday)
{
    date = date.AddMonths(1);
}
Console.WriteLine($"Earliest Friday the 13th: {date:yyyy-MM-dd} ({date.DayOfWeek})");

// Count all Friday the 13ths in a full 400-year cycle (the Gregorian calendar repeats every 400 years)
int count = 0;
var start = new DateTime(1, 1, 13);
var end = new DateTime(401, 1, 1);
var d = start;
while (d < end)
{
    if (d.DayOfWeek == DayOfWeek.Friday)
        count++;
    d = d.AddMonths(1);
}
Console.WriteLine($"Friday the 13ths in a 400-year cycle: {count}");

// Bonus: distribution by day of week for the 13th
Console.WriteLine("\nDistribution of day-of-week for the 13th (400-year cycle):");
var counts = new int[7];
d = start;
while (d < end)
{
    counts[(int)d.DayOfWeek]++;
    d = d.AddMonths(1);
}
foreach (DayOfWeek dow in Enum.GetValues<DayOfWeek>())
{
    Console.WriteLine($"  {dow,-10}: {counts[(int)dow]}");
}

